mapper.insert:
INSERT INTO CHAT_ROOM_USER (
seq, room_id, member_id, joined_at, last_read_at
) VALUES (
SEQ_CHAT_ROOM_USER.NEXTVAL, #{room_id}, #{member_id}, SYSDATE, SYSTIMESTAMP
)

choose.when:
SELECT cr.room_id, cr.room_type, cr.festival_id, cr.owner_id, NVL(cr.room_title, fi.title || ' 공식 모임') AS room_title,
NVL(cr.room_description, NVL(fi.overview, fi.title || ' 공식 모임방입니다.')) AS room_description,
NVL(cr.free_location, fi.addr1) AS free_location, NVL(TO_CHAR(cr.free_date, 'YYYY.MM.DD'), fi.event_start_date || ' ~ ' || fi.event_end_date) AS free_date, NVL(cr.max_capacity, 500) AS max_capacity, cr.created_at, m.nickname, NVL(fi.first_image, m.profile_image_url) AS profile_image_url, (SELECT COUNT(*) FROM chat_room_user cru WHERE cru.room_id = cr.room_id) AS current_count FROM chat_room cr LEFT JOIN member m ON cr.owner_id = m.member_id LEFT JOIN festival_info fi ON cr.festival_id = fi.content_id WHERE cr.room_id = #{roomId}

mapper.insert:
INSERT INTO CHAT_ROOM_USER (
seq, room_id, member_id, joined_at, last_read_at
) VALUES (
SEQ_CHAT_ROOM_USER.NEXTVAL, #{room_id}, #{member_id}, SYSDATE, SYSTIMESTAMP
)
